#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

      // take the difference between the crisp and blurred images,
      // then add it back into the image.  Creates spots and stripes over uTime.
      ret += (ret - GetBlur2(vUv))*0.3;
      ret *= 0.9;

      // add noise:
      vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 0.0 + rand_frame.xy;
      ret += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/856.0 * 112;

      // desaturate over uTime, to keep the globs white
      //ret = mix(ret, lum(ret), 0.2);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // Initialize variables
    vec2 R = uTexSize.xy;
    float FOV = 2.5;

    // Calculate ray direction
    vec3 D = normalize(vec3(1.0/FOV, (vUvOriginal*uAspect.xy*2.0 - uAspect.xy)/uAspect.y));

    // Apply rotation over uTime
    D.xz = multiply(rot(q5), D.xz);      // XZ rotation (main beat-synced)
    D.yz = multiply(rot(q5*0.5), D.yz);  // YZ rotation (float speed)

    // Cubemap simulation and face detection
    vec3 A = abs(D);
    int i = 0;
    float M = A.x;
    if (A.y > M) { M = A.y; i = 1; }
    if (A.z > M) { M = A.z; i = 2; }
    int faceID = i + 3 * int(D[i] < 0.0);

    // Calculate proper UV coordinates for each face
    vec2 cubemapUV;
    if (faceID == 0) cubemapUV = D.zy / abs(D.x); // +X
    else if (faceID == 3) cubemapUV = D.zy / abs(D.x); // -X
    else if (faceID == 1) cubemapUV = D.xz / abs(D.y); // +Y
    else if (faceID == 4) cubemapUV = D.xz / abs(D.y); // -Y
    else if (faceID == 2) cubemapUV = D.xy / abs(D.z); // +Z
    else cubemapUV = D.xy / abs(D.z); // -Z

    // Sample from appropriate texture based on face
    if (faceID == 0) ret = texture(sampler_main, cubemapUV*0.5+0.5).xyz; // +X
    else if (faceID == 1) ret = texture(sampler_main, cubemapUV*0.5+0.5).xyz; // +Y
    else if (faceID == 2) ret = texture(sampler_main, cubemapUV*0.5+0.5).xyz; // +Z
    else if (faceID == 3) ret = texture(sampler_main, cubemapUV*0.5+0.5).xyz; // -X
    else if (faceID == 4) ret = texture(sampler_main, cubemapUV*0.5+0.5).xyz; // -Y
    else ret = texture(sampler_main, cubemapUV*0.5+0.5).xyz; // -Z

    // Apply the blur effect
    vec3 base = ret;
    ret = base*1 + GetBlur1(cubemapUV*0.5+0.5)*3 + GetBlur2(cubemapUV*0.5+0.5)*0 + GetBlur3(cubemapUV*0.5+0.5)*0 + 0;
    ret += GetBlur2( (vUv-0.5)*0.333 + 0.5);
    ret *= 1;

  fragColor = ret;
}
